// TestRegression covers critical library scanning failures
func TestRegression(t *testing.T) {
	t.Run("TrivyDBClientInitializationFailure", testTrivyDBClientInitFail)
	t.Run("MissingPNPMEcosystemDetection", testMissingPNPMEcosystem)
	t.Run("LibraryScannerIntegration", testLibraryScannerIntegration)
	t.Run("TrivyDBClientSignature", testTrivyDBClientSignature)
}

// testTrivyDBClientInitFail demonstrates that the Trivy DB client initialization
// fails with the current code due to missing or incorrect parameters.
// This test verifies that db.NewClient() is called with an incorrect signature.
func testTrivyDBClientInitFail(t *testing.T) {
	tempDir := t.TempDir()

	// The current code calls: db.NewClient(cacheDir, quiet)
	// This test validates the failure
	defer func() {
		// Clean up
		trivydb.Close()
	}()

	// Try to initialize the DB client as the current code does
	// This should demonstrate the API incompatibility
	cacheDir := filepath.Join(tempDir, "trivy-cache")
	if err := os.MkdirAll(cacheDir, 0755); err != nil {
		t.Fatalf("Failed to create cache dir: %v", err)
	}

	// Test the current broken signature
	// The current code does: client := db.NewClient(cacheDir, quiet)
	// But the Trivy API likely requires additional parameters
	t.Logf("Testing db.NewClient with current (broken) parameters: cacheDir=%q, quiet=false", cacheDir)

	// This test demonstrates the issue - if we can't even construct the client,
	// library scanning will fail before attempting any vulnerability detection
	client := db.NewClient(cacheDir, false)
	if client == nil {
		t.Fatal("db.NewClient returned nil, indicating API incompatibility")
	}

	// Test that the client has proper initialization
	// The issue is that the Trivy API has changed to require more parameters
	t.Logf("Client created: %v", client)
}

// testMissingPNPMEcosystem verifies that PNPM lockfiles are not detected
// because the PNPM analyzer is not imported in scanner/base.go
func testMissingPNPMEcosystem(t *testing.T) {
	// Check if PNPM is in the LibraryMap
	pnpmSupported := false
	for filename := range models.LibraryMap {
		if filename == "pnpm-lock.yaml" {
			pnpmSupported = true
			break
		}
	}

	if pnpmSupported {
		t.Fatal("PNPM should not be supported in the current (buggy) codebase")
	}

	t.Log("CONFIRMED: PNPM ecosystem is not supported - pnpm-lock.yaml not in LibraryMap")

	// Verify that PNPM packages would not be detected
	// Create a fake pnpm-lock.yaml to test detection
	tempDir := t.TempDir()
	pnpmLockPath := filepath.Join(tempDir, "pnpm-lock.yaml")

	pnpmContent := `lockfileVersion: 5.4
specifiers:
  express: ^4.18.0
dependencies:
  express: 4.18.1
packages:
  /express/4.18.1:
    dependencies:
      body-parser: 1.20.0
`

	if err := os.WriteFile(pnpmLockPath, []byte(pnpmContent), 0644); err != nil {
		t.Fatalf("Failed to write pnpm-lock.yaml: %v", err)
	}

	// Try to analyze the PNPM file using the current analyzer configuration
	// This should NOT detect the file as a lockfile since PNPM analyzer is not imported
	libFile := struct {
		Contents []byte
		Filemode os.FileMode
	}{
		Contents: []byte(pnpmContent),
		Filemode: 0644,
	}

	// The disabledAnalyzers from scanner/base.go should prevent analysis
	// But since PNPM analyzer was never imported, it won't be available anyway
	disabledAnalyzers := []analyzer.Type{
		analyzer.TypeAlpine,
		analyzer.TypeAlma,
		analyzer.TypeAmazon,
		analyzer.TypeDebian,
		analyzer.TypePhoton,
		analyzer.TypeCentOS,
		analyzer.TypeFedora,
		analyzer.TypeOracle,
		analyzer.TypeRedHatBase,
		analyzer.TypeRocky,
		analyzer.TypeSUSE,
		analyzer.TypeUbuntu,
		analyzer.TypeApk,
		analyzer.TypeDpkg,
		analyzer.TypeRpm,
		analyzer.TypeApkCommand,
		analyzer.TypeYaml,
		analyzer.TypeTOML,
		analyzer.TypeJSON,
		analyzer.TypeDockerfile,
		analyzer.TypeHCL,
		analyzer.TypeSecret,
	}

	anal := analyzer.NewAnalyzerGroup(analyzer.GroupBuiltin, disabledAnalyzers)

	var wg sync.WaitGroup
	result := new(analyzer.AnalysisResult)

	err := anal.AnalyzeFile(
		context.Background(),
		&wg,
		semaphore.NewWeighted(1),
		result,
		"",
		pnpmLockPath,
		&DummyFileInfo{size: int64(len(libFile.Contents)), filemode: libFile.Filemode},
		func() (dio.ReadSeekCloserAt, error) { return dio.NopCloser(bytes.NewReader(libFile.Contents)), nil },
		nil,
		analyzer.AnalysisOptions{Offline: false},
	)

	if err != nil {
		t.Logf("Analysis error (expected for PNPM): %v", err)
	}

	wg.Wait()

	// Verify no applications were detected (because PNPM analyzer is not available)
	if len(result.Applications) > 0 {
		t.Logf("Unexpectedly detected applications: %v", result.Applications)
		for _, app := range result.Applications {
			t.Logf("  - Type: %s, FilePath: %s, Libraries: %d", app.Type, app.FilePath, len(app.Libraries))
		}
	} else {
		t.Log("CONFIRMED: PNPM lockfile was not detected (no applications found)")
	}
}

// testLibraryScannerIntegration tests the conversion of fanal applications to
// LibraryScanner models, verifying that the conversion process would work
// if the ecosystem detection worked correctly.
func testLibraryScannerIntegration(t *testing.T) {
	// Test data: simulate what fanal would return if PNPM was supported
	fanalApps := []struct {
		Type     string
		FilePath string
		Libs     []string
	}{
		{
			Type:     "npm",
			FilePath: "package-lock.json",
			Libs:     []string{"express@4.18.1", "lodash@4.17.21"},
		},
		{
			// This PNPM case would fail due to missing ecosystem support
			Type:     "pnpm",
			FilePath: "pnpm-lock.yaml",
			Libs:     []string{"express@4.18.1"},
		},
	}

	// Attempt to convert using the current code
	// The NPM one should work, but the PNPM one won't be detected
	t.Logf("Testing LibraryScanner conversion for %d application types", len(fanalApps))

	for _, app := range fanalApps {
		t.Logf("Testing conversion for type=%q, filepath=%q", app.Type, app.FilePath)

		// Verify that PNPM type is not handled
		if app.Type == "pnpm" {
			// This type should not be in the Library ecosystem list
			key := app.FilePath
			mappedType, exists := models.LibraryMap[key]

			if exists {
				t.Logf("ERROR: PNPM file %q should not be in LibraryMap, but found mapping to %q", key, mappedType)
			} else {
				t.Logf("CONFIRMED: PNPM file %q is not in LibraryMap", key)
			}
		}
	}
}

// testTrivyDBClientSignature specifically tests that the db.NewClient
// is called with the wrong number of parameters in detector/library.go
func testTrivyDBClientSignature(t *testing.T) {
	// This test documents the API incompatibility
	// The current code does: client := db.NewClient(cacheDir, quiet)
	//
	// According to the issue, the Trivy API has added a required parameter
	// that the scanner does not provide, causing initialization to fail.

	tempDir := t.TempDir()
	cacheDir := filepath.Join(tempDir, "trivy-cache")
	if err := os.MkdirAll(cacheDir, 0755); err != nil {
		t.Fatalf("Failed to create cache dir: %v", err)
	}

	// Test calling NewClient with current parameters
	// The signature in detector/library.go line 66 is:
	//   client := db.NewClient(cacheDir, quiet)
	//
	// However, the Trivy API likely requires:
	//   client := db.NewClient(cacheDir, quiet, appVersion)
	// or similar with additional parameters

	t.Logf("Current code signature: db.NewClient(cacheDir=%q, quiet=false)", cacheDir)
	t.Log("Expected to fail if Trivy API has changed to require additional parameters")

	// Attempt to create client with current signature
	client := db.NewClient(cacheDir, false)

	if client == nil {
		t.Fatal("NewClient returned nil - indicates API incompatibility or initialization failure")
	}

	// If we got here, the client was created, but this might be with a default
	// for a missing parameter. The actual failure would occur during usage.
	t.Logf("Client created successfully: %v (may fail during actual use)", client)
}

// DummyFileInfo is a dummy implementation of os.FileInfo for testing
type DummyFileInfo struct {
	size     int64
	filemode os.FileMode
}

func (d *DummyFileInfo) Name() string       { return "dummy" }
func (d *DummyFileInfo) Size() int64        { return d.size }
func (d *DummyFileInfo) Mode() os.FileMode  { return d.filemode }
func (d *DummyFileInfo) ModTime() os.Time   { return time.Now() }
func (d *DummyFileInfo) IsDir() bool        { return false }
func (d *DummyFileInfo) Sys() interface{}   { return nil }

// Additional test: Verify scan library analyzer imports
func TestLibraryAnalyzerImports(t *testing.T) {
	t.Run("VerifyPNPMNotImported", func(t *testing.T) {
		// This test documents that the PNPM analyzer is not imported
		// See scanner/base.go lines 31-43 for the list of imported analyzers
		// PNPM is missing from this list

		importedAnalyzers := map[string]bool{
			"nuget":    true,  // line 31
			"gobinary": true,  // line 32
			"gomod":    true,  // line 33
			"jar":      true,  // line 34
			"pom":      true,  // line 35
			"npm":      true,  // line 36
			"yarn":     true,  // line 37
			"composer": true,  // line 38
			"pip":      true,  // line 39
			"pipenv":   true,  // line 40
			"poetry":   true,  // line 41
			"bundler":  true,  // line 42
			"cargo":    true,  // line 43
			// PNPM is missing!
		}

		pnpmImported := importedAnalyzers["pnpm"]
		if pnpmImported {
			t.Fatal("PNPM analyzer should not be imported based on issue description")
		}

		t.Log("CONFIRMED: PNPM analyzer is not imported in scanner/base.go")
	})
}

// Import time for the test
import "time"

// TestLibraryMapMissingEcosystems verifies that certain package ecosystems
// are missing from the LibraryMap, preventing their detection
func TestLibraryMapMissingEcosystems(t *testing.T) {
	missingEcosystems := []string{
		"pnpm-lock.yaml",
		"pnpm-lock.json",
	}

	for _, ecosystem := range missingEcosystems {
		_, exists := models.LibraryMap[ecosystem]
		if exists {
			t.Errorf("Ecosystem %q should not be in LibraryMap (bug #2)", ecosystem)
		} else {
			t.Logf("CONFIRMED: Ecosystem %q is missing from LibraryMap", ecosystem)
		}
	}

	// Also verify that .NET is present (it should be)
	netSupported := false
	for filename := range models.LibraryMap {
		if filename == "packages.config" || filename == "packages.lock.json" {
			netSupported = true
			t.Logf(".NET ecosystem supported: %q -> %q", filename, models.LibraryMap[filename])
		}
	}

	if !netSupported {
		t.Log("Note: .NET support is present in LibraryMap")
	}
}

// TestConvertLibWithScanner tests the library conversion function
// to ensure it properly converts fanal applications to LibraryScanner models
func TestConvertLibWithScanner(t *testing.T) {
	// This test verifies that the scanner.convertLibWithScanner function works
	// but would fail to detect PNPM files due to missing ecosystem support

	// Create test data similar to what fanal would return
	testCases := []struct {
		name     string
		libType  string
		lockFile string
		libs     []string
	}{
		{
			name:     "NPM packages",
			libType:  "npm",
			lockFile: "package-lock.json",
			libs:     []string{"express", "lodash"},
		},
		{
			name:     "PNPM packages (unsupported)",
			libType:  "pnpm",
			lockFile: "pnpm-lock.yaml",
			libs:     []string{"express"},
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			t.Logf("Testing conversion for %s lockfile", tc.name)

			// Check if the lockfile is in LibraryMap
			libraryType, exists := models.LibraryMap[tc.lockFile]

			if tc.libType == "pnpm" {
				if exists {
					t.Errorf("PNPM lockfile %q should not be in LibraryMap, but found: %q", tc.lockFile, libraryType)
				} else {
					t.Logf("CONFIRMED: %s is not supported - missing from LibraryMap", tc.name)
				}
			} else {
				if !exists {
					t.Errorf("Expected %s to be in LibraryMap", tc.lockFile)
				} else {
					t.Logf("%s detected as type: %q", tc.lockFile, libraryType)
				}
			}
		})
	}
}

