		analyzer.TypeApk,
		analyzer.TypeDpkg,
		analyzer.TypeRpm,
		analyzer.TypeApkCommand,
		analyzer.TypeYaml,
		analyzer.TypeTOML,
		analyzer.TypeJSON,
		analyzer.TypeDockerfile,
		analyzer.TypeHCL,
		analyzer.TypeSecret,
	}

	anal := analyzer.NewAnalyzerGroup(analyzer.GroupBuiltin, disabledAnalyzers)

	if anal == nil {
		t.Fatal("Failed to create analyzer group")
	}

	t.Logf("✓ Analyzer group created with %d disabled analyzer types", len(disabledAnalyzers))
	t.Log("✓ Scope control is properly implemented to exclude non-library analyzers")
	t.Log("✗ ISSUE: Ecosystem support is incomplete - PNPM is missing")
}

// testTrivyDBClientSignature specifically tests the db.NewClient signature
// as called from detector/library.go line 66
func testTrivyDBClientSignature(t *testing.T) {
	// Current code (detector/library.go line 66):
	//   client := db.NewClient(cacheDir, quiet)
	//
	// The Trivy API has changed and may require additional parameters:
	//   - appVersion parameter
	//   - repository parameter
	//   - other configuration options

	tempDir := t.TempDir()
	cacheDir := filepath.Join(tempDir, "trivy-cache")
	if err := os.MkdirAll(cacheDir, 0755); err != nil {
		t.Fatalf("Failed to create cache dir: %v", err)
	}

	t.Logf("Current signature: db.NewClient(cacheDir=%q, quiet=false)", cacheDir)
	t.Log("Testing if Trivy API signature has changed...")

	// Attempt to create client with current signature
	client := db.NewClient(cacheDir, false)

	if client == nil {
		t.Fatal("NewClient returned nil - indicates API incompatibility")
	}

	// If we got here, basic creation worked, but there may be runtime issues
	t.Logf("Client created: %v", client)
	t.Log("Note: Runtime failures may occur if API changes require additional parameters")
}

